class Solution:
    def countSubstrings(self, s, t):
        n, m = len(s), len(t)
        count = 0
        for i in range(n):
            for length in range(1, n - i + 1):
                sub_s = s[i:i + length]
                for j in range(m - length + 1):
                    sub_t = t[j:j + length]
                    diff = 0
                    for a, b in zip(sub_s, sub_t):
                        if a != b:
                            diff += 1
                    if diff == 1:
                        count += 1
        return count

