var countSubstrings = function(s, t) {
    const n = s.length, m = t.length;
    let count = 0;
    for (let i = 0; i < n; i++) {
        for (let j = 0; j < m; j++) {
            let diff = 0;
            let k = 0;
            while (i + k < n && j + k < m) {
                if (s[i + k] !== t[j + k]) {
                    diff++;
                    if (diff > 1) break;
                }
                if (diff === 1) count++;
                k++;
            }
        }
    }
    return count;
};
